namespace sv_f138215a6487455a86e9af688e08ed49.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_f138215a6487455a86e9af688e08ed49.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-description">@Channel.Description</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel.Id);
}

.channel-item {
    display: flex;
    flex-direction: column;
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 6px;
    position: relative;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-description {
    font-size: 0.75rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 1px;
}

.unread-badge {
    position: absolute;
    top: 10px;
    right: 10px;
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    min-width: 18px;
    height: 18px;
    line-height: 18px;
    text-align: center;
    border-radius: 9px;
    padding: 0 5px;
}

@using sv_f138215a6487455a86e9af688e08ed49.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background-color: #2c2f33;
    color: #e0e0e0;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #3a3d42;
}

.sidebar-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 6px 0;
}

.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background-color: #fff;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #5865f2;
}

.send-button {
    background-color: #5865f2;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 18px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-button:hover:not(:disabled) {
    background-color: #4752c4;
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

