arguments.file_text:
@using sv_f138215a6487455a86e9af688e08ed49.Services

<div class="message-area">
    <div class="area-header">
        <h5># @ChannelName</h5>
        <span class="area-description">@ChannelDescription</span>
    </div>

    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnReply="OnOpenThread"
                           OnViewThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonLabel="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers load more via JS interop-free approach:
        // We detect this via a small sentinel at the top; for simplicity,
        // the parent provides a "Load More" experience triggered here.
        await OnLoadMore.InvokeAsync();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #fff;
}

.area-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h5 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #2c2f33;
}

.area-description {
    font-size: 0.8rem;
    color: #777;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 10px;
    font-size: 0.8rem;
    color: #999;
}

@using sv_f138215a6487455a86e9af688e08ed49.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    <div class="thread-root-quote">
        <span class="quote-author">@RootMessage.Author</span>
        <p class="quote-content">@RootMessage.Content</p>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <MessageBubble Message="reply" ShowActions="false" />
        }
    </div>

    <MessageInput Placeholder="Reply…"
                  ButtonLabel="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

