arguments.file_text:
@page "/chat"
@using sv_f138215a6487455a86e9af688e08ed49.Services
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannelAsync" />
    </div>

    <div class="chat-main @(threadRootMessage is null ? "expanded" : "")">
        @if (activeChannel is not null)
        {
            <MessageArea ChannelName="@activeChannel.Name"
                         ChannelDescription="@activeChannel.Description"
                         Messages="messages"
                         ThreadReplyCounts="threadReplyCounts"
                         IsLoadingMore="isLoadingMore"
                         OnLoadMore="LoadMoreMessagesAsync"
                         OnSendMessage="SendMessageAsync"
                         OnOpenThread="OpenThreadAsync"
                         OnReact="HandleReactAsync" />
        }
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReplyAsync" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? activeChannel;
    private int activeChannelId;
    private List<Message> messages = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        if (activeChannelId == channelId) return;

        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadReplyCounts = [];
        hasMoreMessages = true;
        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        BuildThreadReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh unread count in sidebar
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        messages.InsertRange(0, older);
        BuildThreadReplyCounts();
        isLoadingMore = false;
    }

    private async Task SendMessageAsync(string content)
    {
        var newMsg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(newMsg);
    }

    private async Task OpenThreadAsync(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update reply count shown in main message list
        threadReplyCounts[threadRootMessage.Id] =
            threadReplyCounts.GetValueOrDefault(threadRootMessage.Id) + 1;
    }

    private async Task HandleReactAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        var refreshed = await ChatService.GetMessagesAsync(
            activeChannelId, 0, messages.Count);
        messages = refreshed;
    }

    private void BuildThreadReplyCounts()
    {
        // Count messages that are replies (have ReplyToId set) grouped by root
        threadReplyCounts = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    transition: flex 0.2s;
}

.chat-main.expanded {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

